// Solution
function isValidHTML(s) {
    let stack = [];
    let i = 0;
    while (i < s.length) {
        if (s[i] === '<') {
            let j = s.indexOf('>', i);
            if (j === -1) {
                return false;
            }
            let tag = s.substring(i + 1, j);
            if (tag[0] === '/') {
                if (stack.length === 0 || stack.pop() !== tag.substring(1)) {
                    return false;
                }
            } else {
                stack.push(tag);
            }
            i = j + 1;
        } else {
            i++;
        }
    }
    return stack.length === 0;
}

