class Solution:
    def isValidHTML(self, s: str) -> bool:
        stack = []
        i = 0
        while i < len(s):
            if s[i] == '<':
                j = s.find('>', i)
                if j == -1:
                    return False
                tag = s[i + 1:j]
                if tag[0] == '/':
                    if not stack or stack.pop() != tag[1:]:
                        return False
                else:
                    stack.append(tag)
                i = j + 1
            else:
                i += 1
        return len(stack) == 0
